func extractLineNo(re *regexp.Regexp) lineNumberExtractor {
	return func(e error) (int, int) {
		if e == nil {
			panic("no error")
		}
		col := 1
		s := e.Error()
		m := re.FindStringSubmatch(s)
		if len(m) >= 2 {
			lno, _ := strconv.Atoi(m[1])
			if len(m) > 2 {
				col, _ = strconv.Atoi(m[2])
			}

			if col <= 0 {
				col = 1
			}

			return lno, col
		}

		return 0, col
	}
}
